-- Azianline commerce schema. Apply with: supabase db push
create extension if not exists "pgcrypto";
create type public.user_role as enum ('customer','admin','super_admin');
create type public.order_status as enum ('pending','confirmed','processing','shipped','delivered','cancelled','refunded');
create type public.payment_status as enum ('pending','authorized','paid','failed','refunded');
create table public.profiles(id uuid primary key references auth.users on delete cascade, role public.user_role not null default 'customer', full_name text, phone text, avatar_url text, is_disabled boolean not null default false, created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.categories(id uuid primary key default gen_random_uuid(), parent_id uuid references public.categories on delete restrict, name text not null, slug text unique not null, description text, image_url text, seo_title text, seo_description text, sort_order integer not null default 0, active boolean not null default true, created_at timestamptz not null default now());
create table public.brands(id uuid primary key default gen_random_uuid(), name text unique not null, slug text unique not null, logo_url text, description text, website text, country text, active boolean not null default true, featured boolean not null default false, created_at timestamptz not null default now());
create table public.products(id uuid primary key default gen_random_uuid(), brand_id uuid references public.brands on delete restrict, category_id uuid references public.categories on delete restrict, name text not null, slug text unique not null, sku text unique not null, short_description text, description jsonb not null default '{}'::jsonb, price numeric(12,2) not null check(price>=0), compare_at_price numeric(12,2) check(compare_at_price is null or compare_at_price>=price), cost_price numeric(12,2) check(cost_price is null or cost_price>=0), tax_rate numeric(5,2) not null default 0 check(tax_rate>=0), status text not null default 'draft' check(status in ('draft','active','archived')), featured boolean not null default false,best_seller boolean not null default false,new_arrival boolean not null default false, seo_title text,seo_description text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.product_images(id uuid primary key default gen_random_uuid(), product_id uuid not null references public.products on delete cascade, url text not null, alt_text text, sort_order integer not null default 0);
create table public.product_variants(id uuid primary key default gen_random_uuid(), product_id uuid not null references public.products on delete cascade, sku text unique not null, title text not null, options jsonb not null default '{}'::jsonb, price numeric(12,2), image_url text, active boolean not null default true);
create table public.inventory(id uuid primary key default gen_random_uuid(), product_id uuid not null references public.products on delete cascade, variant_id uuid unique references public.product_variants on delete cascade, quantity integer not null default 0 check(quantity>=0), reserved_quantity integer not null default 0 check(reserved_quantity>=0 and reserved_quantity<=quantity), low_stock_limit integer not null default 5 check(low_stock_limit>=0), updated_at timestamptz not null default now(), unique(product_id,variant_id));
create table public.inventory_movements(id uuid primary key default gen_random_uuid(), inventory_id uuid not null references public.inventory on delete cascade, delta integer not null, reason text not null, actor_id uuid references public.profiles on delete set null, created_at timestamptz not null default now());
create table public.addresses(id uuid primary key default gen_random_uuid(), profile_id uuid not null references public.profiles on delete cascade, label text, recipient_name text not null, line1 text not null,line2 text,city text not null,region text,postal_code text, country_code text not null, phone text, is_default boolean not null default false,created_at timestamptz not null default now());
create table public.carts(id uuid primary key default gen_random_uuid(), profile_id uuid unique references public.profiles on delete cascade, session_key text unique, currency text not null default 'EUR',updated_at timestamptz not null default now(),check(profile_id is not null or session_key is not null));
create table public.cart_items(id uuid primary key default gen_random_uuid(),cart_id uuid not null references public.carts on delete cascade,product_id uuid not null references public.products on delete restrict,variant_id uuid references public.product_variants on delete restrict,quantity integer not null check(quantity>0),unique(cart_id,product_id,variant_id));
create table public.wishlists(id uuid primary key default gen_random_uuid(), profile_id uuid unique not null references public.profiles on delete cascade,created_at timestamptz not null default now());
create table public.wishlist_items(id uuid primary key default gen_random_uuid(),wishlist_id uuid not null references public.wishlists on delete cascade,product_id uuid not null references public.products on delete cascade,created_at timestamptz not null default now(),unique(wishlist_id,product_id));
create table public.coupons(id uuid primary key default gen_random_uuid(),code text unique not null,description text,kind text not null check(kind in ('percent','fixed','free_shipping')),amount numeric(12,2) not null check(amount>=0),minimum_order numeric(12,2) not null default 0,maximum_discount numeric(12,2),starts_at timestamptz,ends_at timestamptz,usage_limit integer,per_user_limit integer,active boolean not null default true,created_at timestamptz not null default now());
create table public.orders(id uuid primary key default gen_random_uuid(), number bigint generated always as identity unique,profile_id uuid references public.profiles on delete set null,email text not null,status public.order_status not null default 'pending',payment_status public.payment_status not null default 'pending',currency text not null default 'EUR',subtotal numeric(12,2) not null,discount_total numeric(12,2) not null default 0,shipping_total numeric(12,2) not null default 0,tax_total numeric(12,2) not null default 0,total numeric(12,2) not null,shipping_address jsonb not null,payment_provider text, idempotency_key text unique,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.order_items(id uuid primary key default gen_random_uuid(),order_id uuid not null references public.orders on delete restrict,product_id uuid references public.products on delete set null,variant_id uuid references public.product_variants on delete set null,name text not null,sku text not null,unit_price numeric(12,2) not null,quantity integer not null check(quantity>0),line_total numeric(12,2) not null);
create table public.order_status_history(id uuid primary key default gen_random_uuid(),order_id uuid not null references public.orders on delete cascade,status public.order_status not null,note text,actor_id uuid references public.profiles on delete set null,created_at timestamptz not null default now());
create table public.payments(id uuid primary key default gen_random_uuid(),order_id uuid not null references public.orders on delete cascade,provider text not null,provider_reference text,status public.payment_status not null default 'pending',amount numeric(12,2) not null,created_at timestamptz not null default now());
create table public.reviews(id uuid primary key default gen_random_uuid(),product_id uuid not null references public.products on delete cascade,profile_id uuid not null references public.profiles on delete cascade,rating smallint not null check(rating between 1 and 5),title text,body text not null,status text not null default 'pending' check(status in ('pending','published','hidden','reported')),admin_response text,helpful_count integer not null default 0,verified_purchase boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(product_id,profile_id));
create table public.review_images(id uuid primary key default gen_random_uuid(),review_id uuid not null references public.reviews on delete cascade,url text not null);
create table public.review_helpful_votes(review_id uuid references public.reviews on delete cascade,profile_id uuid references public.profiles on delete cascade,primary key(review_id,profile_id));
create table public.review_reports(id uuid primary key default gen_random_uuid(),review_id uuid not null references public.reviews on delete cascade,profile_id uuid references public.profiles on delete set null,reason text not null,created_at timestamptz not null default now());
create table public.banners(id uuid primary key default gen_random_uuid(),title text not null,subtitle text,image_url text,cta_label text,cta_url text,active boolean not null default true,starts_at timestamptz,ends_at timestamptz,sort_order integer not null default 0);
create table public.newsletter_subscribers(id uuid primary key default gen_random_uuid(),email text unique not null,locale text not null default 'en',consented_at timestamptz not null default now(),unsubscribed_at timestamptz);
create table public.recently_viewed_products(profile_id uuid references public.profiles on delete cascade,product_id uuid references public.products on delete cascade,viewed_at timestamptz not null default now(),primary key(profile_id,product_id));
create table public.notifications(id uuid primary key default gen_random_uuid(),profile_id uuid not null references public.profiles on delete cascade,type text not null,payload jsonb not null default '{}'::jsonb,read_at timestamptz,created_at timestamptz not null default now());
create table public.site_settings(key text primary key,value jsonb not null,updated_at timestamptz not null default now());
create index products_catalog_idx on public.products(category_id,status,featured); create index order_profile_idx on public.orders(profile_id,created_at desc); create index review_product_idx on public.reviews(product_id,status,created_at desc);
alter table public.profiles enable row level security; alter table public.addresses enable row level security; alter table public.carts enable row level security; alter table public.cart_items enable row level security; alter table public.wishlists enable row level security; alter table public.wishlist_items enable row level security; alter table public.orders enable row level security; alter table public.order_items enable row level security; alter table public.reviews enable row level security;
create policy "profile own" on public.profiles for all using (auth.uid()=id) with check(auth.uid()=id); create policy "address own" on public.addresses for all using (profile_id=auth.uid()) with check(profile_id=auth.uid()); create policy "cart own" on public.carts for all using(profile_id=auth.uid()) with check(profile_id=auth.uid()); create policy "wishlist own" on public.wishlists for all using(profile_id=auth.uid()) with check(profile_id=auth.uid()); create policy "orders own" on public.orders for select using(profile_id=auth.uid()); create policy "published reviews readable" on public.reviews for select using(status='published' or profile_id=auth.uid()); create policy "review own insert" on public.reviews for insert with check(profile_id=auth.uid());
